/* BTBreadcrumb — Figma node 681:10168 (web D) */
/* All CSS vars verified against packages/tokens/platforms/web/bspace/dist/styles.css */

/* ── Nav wrapper ──────────────────────────────────────────────────────────── */

.bt-breadcrumb {
  display: flex;
  align-items: center;
}

/* ── Ordered list ─────────────────────────────────────────────────────────── */

.bt-breadcrumb-list {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: var(--space-sm);
  list-style: none;
  margin: 0;
  padding: 0;
}

/* ── Individual item (li) ─────────────────────────────────────────────────── */

.bt-breadcrumb-item {
  display: inline-flex;
  align-items: center;
  gap: var(--space-xs);
}

/* ── Current (last) item — non-interactive ────────────────────────────────── */

.bt-breadcrumb-page {
  font-size: var(--typography-font-size-sm);
  font-weight: 500;
  line-height: 1.14;
  color: var(--text-primary);
}

/* ── Separator icon ───────────────────────────────────────────────────────── */

.bt-breadcrumb-separator {
  display: inline-flex;
  align-items: center;
  color: var(--text-secondary);
}

.bt-breadcrumb-separator__icon {
  width: 6px;
  height: 10px;
}

[dir="rtl"] .bt-breadcrumb-separator__icon {
  transform: scaleX(-1);
}

/* ── Ellipsis trigger (···) ───────────────────────────────────────────────── */

.bt-breadcrumb-ellipsis {
  position: relative;
  display: inline-flex;
}

.bt-breadcrumb-ellipsis__btn {
  width: 24px;
  height: 24px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border-radius: var(--radius-sm);
  background: none;
  border: none;
  cursor: pointer;
  color: var(--text-secondary);
  padding: 0;
  transition: background 0.15s ease;
}

.bt-breadcrumb-ellipsis__btn:hover,
.bt-breadcrumb-ellipsis__btn[aria-expanded="true"] {
  background: var(--bg-secondary);
}

.bt-breadcrumb-ellipsis__icon {
  width: 16px;
  height: 4px;
}

// BTBreadcrumb compositional types — Figma node 681:10168 (web D).

export interface BTBreadcrumbProps {
  class?: string;
}

export interface BTBreadcrumbListProps {
  class?: string;
}

export interface BTBreadcrumbItemProps {
  class?: string;
}

export interface BTBreadcrumbLinkProps {
  /** URL to navigate to. When provided renders an <a> element. */
  href?: string;
  /** Programmatic press handler. When href is also set, prevents default navigation. */
  onPress?: () => void;
  class?: string;
}

export interface BTBreadcrumbPageProps {
  class?: string;
}

export interface BTBreadcrumbSeparatorProps {
  class?: string;
}

/** A single item shown inside the BTBreadcrumbEllipsis dropdown list. */
export interface BTBreadcrumbDropdownItem {
  /** Display label shown in the list row. */
  label: string;
  /** Called when the user selects this item. */
  onPress?: () => void;
}

export interface BTBreadcrumbEllipsisProps {
  /** Collapsed breadcrumb items shown inside the BTDropdownList dropdown. */
  items: BTBreadcrumbDropdownItem[];
  class?: string;
}

export { default as BTBreadcrumb } from './BTBreadcrumb.vue';
export { default as BTBreadcrumbList } from './BTBreadcrumbList.vue';
export { default as BTBreadcrumbItem } from './BTBreadcrumbItem.vue';
export { default as BTBreadcrumbLink } from './BTBreadcrumbLink.vue';
export { default as BTBreadcrumbPage } from './BTBreadcrumbPage.vue';
export { default as BTBreadcrumbSeparator } from './BTBreadcrumbSeparator.vue';
export { default as BTBreadcrumbEllipsis } from './BTBreadcrumbEllipsis.vue';
export type {
  BTBreadcrumbProps,
  BTBreadcrumbListProps,
  BTBreadcrumbItemProps,
  BTBreadcrumbLinkProps,
  BTBreadcrumbPageProps,
  BTBreadcrumbSeparatorProps,
  BTBreadcrumbEllipsisProps,
  BTBreadcrumbDropdownItem,
} from './BTBreadcrumb.types';
